function GitHubTrending() {
  const [repos, setRepos] = React.useState([]);
  const [lang, setLang] = React.useState('');
  const [loading, setLoading] = React.useState(false);

  React.useEffect(()=>{
    setLoading(true);
    const url = lang
      ? `https://api.github.com/search/repositories?q=stars:>1000+language:${lang}&sort=stars&order=desc&per_page=15`
      : 'https://api.github.com/search/repositories?q=stars:>5000&sort=stars&order=desc&per_page=15';
    fetch(url)
      .then(r=>r.json())
      .then(d=>{setRepos(d.items||[]);setLoading(false);})
      .catch(()=>setLoading(false));
  },[lang]);

  const languages = ['','JavaScript','Python','TypeScript','Rust','Go','Java','C++','Ruby'];

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <span style={{fontSize:18,fontWeight:700}}>GitHub Trending</span>
        <select value={lang} onChange={e=>setLang(e.target.value)}
          style={{padding:'4px 8px',borderRadius:6,border:'1px solid #ccc',fontSize:13}}>
          {languages.map(l=><option key={l} value={l}>{l||'All Languages'}</option>)}
        </select>
      </div>
      {loading && <div style={{textAlign:'center',color:'#888'}}>Loading…</div>}
      <div style={{flex:1,overflow:'auto'}}>
        {repos.map(r=> (
          <a key={r.id} href={r.html_url} target="_blank" rel="noopener noreferrer"
            style={{display:'block',padding:'8px 0',borderBottom:'1px solid #eee',textDecoration:'none',color:'inherit'}}>
            <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:2}}>
              <span style={{fontSize:14,fontWeight:600,color:'#0969DA'}}>{r.full_name}</span>
              <span style={{fontSize:11,padding:'2px 6px',background:'#ddf4ff',color:'#0969DA',borderRadius:10}}>{r.language}</span>
            </div>
            <div style={{fontSize:12,color:'#888'}}>{r.description?.slice(0,80)}…</div>
            <div style={{fontSize:12,color:'#888',marginTop:2}}>⭐ {r.stargazers_count?.toLocaleString()} · 🍴 {r.forks_count?.toLocaleString()}</div>
          </a>
        ))}
      </div>
    </div>
  );
}
render(<GitHubTrending/>);
